// Build lookup map at module load time
const CEFR_WORD_MAP = new Map<string, CEFRLevel>()
for (const [level, words] of Object.entries(LEVEL_WORDS) as [CEFRLevel, readonly string[]][]) {
  for (const w of words) CEFR_WORD_MAP.set(w, level)
}

export function getCEFRLevel(word: string): CEFRLevel | null {
  return CEFR_WORD_MAP.get(word) ?? null
}

export { CEFR_WORD_MAP }
